  industry: '',
  brandName: '', 
  brandType: 'enterprise',
  services: '',
  website: '',
  productInfo: '',
  brandTone: 'Professional',
  persona: '',
  brandColors: ['#000000', '#ffffff', '#cccccc'],
  targetAudience: '',
  visualStyle: 'minimalist',
  facebookPageId: '',
  facebookToken: '',
  threadsAccounts: [], 
  referenceFiles: [],
  fixedHashtags: '',
  autoReply: { enabled: false, defaultResponse: '', rules: [] },
  autoPilot: {
    enabled: false,
    frequency: 'daily',
    postTime: '09:00',
    source: 'trending',
    keywords: [],
    mediaTypePreference: 'image'
