      if (initialTopic) {
          setActiveTab('generator');
      }
  }, [initialTopic]);

  const handleAccountsChange = (newAccounts: ThreadsAccount[]) => {
      setAccounts(newAccounts);
      onSaveSettings({ ...settings, threadsAccounts: newAccounts });
