          <OpportunityScout 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}

      {activeTab === 'interaction' && (
          <InteractionManager 
              accounts={accounts} 
              user={user} 
              onQuotaUpdate={onQuotaUpdate} 
          />
      )}

      {activeTab === 'generator' && (
          <ContentGenerator 
              settings={settings} 
              accounts={accounts} 
              onQuotaUpdate={onQuotaUpdate} 
              initialTopic={initialTopic}
          />
      )}

      {activeTab === 'dna_lab' && (
          <DigitalDNALab 
              accounts={accounts}
              user={user}
              onQuotaUpdate={onQuotaUpdate}
          />
      )}
    </div>
  );
};

