     if (!isMock) {
         const doc = await db.collection('users').doc(userId).get();
         if(doc.exists) await db.collection('users').doc(userId).update({ isSuspended: !doc.data()?.isSuspended });
     }
};

export const resetUserQuota = async (userId: string) => {
    if (!isMock) await db.collection('users').doc(userId).update({ quota_used: 0 });
};

// --- REAL STATS IMPLEMENTATION ---
export const getDashboardStats = async (): Promise<DashboardStats> => {
    // Default stats
    const stats: DashboardStats = { totalUsers: 0, activeUsersToday: 0, totalApiCallsToday: 0, errorCountToday: 0 };

    if (!isMock) { 
        try {
            // 1. Total Users (Approximation from list for now)
            const usersSnap = await db.collection('users').get();
            stats.totalUsers = usersSnap.size;

            // 2. Active Users Today (DAU)
            const startOfDay = new Date();
            startOfDay.setHours(0,0,0,0);
            const activeSnap = await db.collection('users').where('last_api_call_timestamp', '>', startOfDay.getTime()).get();
            stats.activeUsersToday = activeSnap.size;

            // 3. API Usage (From System Stats Doc)
            const doc = await db.collection('system_stats').doc('api_usage').get(); 
            if (doc.exists) stats.totalApiCallsToday = doc.data()?.total_calls || 0; 

        } catch(e) {
            console.warn("Stats fetch partial failure", e);
        }
    } else {
        // Mock
        const users = await getAllUsers();
        stats.totalUsers = users.length;
        stats.activeUsersToday = Math.floor(users.length * 0.4);
        stats.totalApiCallsToday = 342;
    }
    return stats;
};

// --- REAL LOGS IMPLEMENTATION ---
export const getSystemLogs = async (): Promise<LogEntry[]> => {
    if (!isMock) {
        try {
            const snap = await db.collection('usage_logs')
                .orderBy('ts', 'desc')
                .limit(50)
                .get();

            return snap.docs.map((doc: any) => {
                const data = doc.data();
                // Map usage_log format to LogEntry format for UI
                return {
                    id: doc.id,
                    timestamp: data.ts,
                    userEmail: data.uid, // We store uid mostly, in real app we'd map to email
                    action: data.act,
                    status: (data.res && data.res.startsWith('Error')) ? 'error' : 'success',
                    details: `${data.topic || ''} ${data.prmt ? '(' + data.prmt.substring(0,20) + '...)' : ''}`
                } as LogEntry;
            });
        } catch (e) {
            console.warn("Logs fetch failed", e);
            return [];
        }
    }
    return [];
};

export const getSystemConfig = (): SystemConfig => {
    return MockStore.getConfig();
};

export const updateSystemConfig = (config: Partial<SystemConfig>) => {
    const current = MockStore.getConfig();
    MockStore.saveConfig({ ...current, ...config });
};

import { useState, useEffect } from 'react';
import { 
  getAllUsers, generateAdminKey, 
  getDashboardStats, getSystemLogs, getSystemConfig, updateSystemConfig, 
  getUserReports
} from '../../../services/authService';
import { getApiServiceStatus } from '../../../services/geminiService';
import { db, isMock } from '../../../services/firebase';
import { UserProfile, UserRole, DashboardStats, LogEntry, SystemConfig, UserReport } from '../../../types';

export const useAdminDashboard = (currentUser: UserProfile) => {
    const [activeTab, setActiveTab] = useState<'dashboard' | 'users' | 'api_monitor' | 'reports' | 'system' | 'keys'>('dashboard');

    // Data State
    const [stats, setStats] = useState<DashboardStats | null>(null);
    const [users, setUsers] = useState<UserProfile[]>([]);
    const [reports, setReports] = useState<UserReport[]>([]);
    const [apiUsage, setApiUsage] = useState<any>(null);
    const [apiStatus, setApiStatus] = useState<{ 
        keyStatus: boolean[]; 
        providers: { openai: boolean; ideogram: boolean; grok: boolean; };
    }>({ 
        keyStatus: [], 
        providers: { openai: false, ideogram: false, grok: false } 
    }); 
    const [logs, setLogs] = useState<LogEntry[]>([]);
    const [config, setConfig] = useState<SystemConfig>({ maintenanceMode: false, dryRunMode: false });
    const [generatedKey, setGeneratedKey] = useState('');

    // Modal State
    const [securityTarget, setSecurityTarget] = useState<{uid: string, type: 'DOWNLOAD'|'DELETE'} | null>(null);

    // UI Status
    const [loadingAction, setLoadingAction] = useState(false); 
    const [dataLoading, setDataLoading] = useState(true);
    const [dataError, setDataError] = useState('');

    useEffect(() => {
        loadAllData();
    }, []);

    useEffect(() => {
        let timer: any;
        if (activeTab === 'api_monitor') {
            loadApiUsage();
            timer = setInterval(loadApiUsage, 5000);
        }
        return () => { if(timer) clearInterval(timer); };
    }, [activeTab]);

    const loadAllData = async () => {
        setDataLoading(true);
        setDataError('');
        try {
            const statsData = await getDashboardStats();
            setStats(statsData);
            setUsers(await getAllUsers());
            setLogs(await getSystemLogs());
            setConfig(getSystemConfig());
            setReports(await getUserReports());
        } catch (e: any) {
            console.error("Dashboard Load Error:", e);
            setDataError(e.message || "資料讀取失敗");
        } finally {
            setDataLoading(false);
        }
    };

    const loadApiUsage = async () => {
        try {
            const statusData = await getApiServiceStatus();
            setApiStatus(statusData);

            if (isMock) {
                setApiUsage({ key_1: 1250, key_2: 890, key_3: 450, key_4: 120, key_5: 5, total_calls: 2715 });
                return;
            }
            const doc = await db.collection('system_stats').doc('api_usage').get();
            if (doc.exists) setApiUsage(doc.data());
        } catch (e) { console.error("Load API Usage failed", e); }
    };

    const handleGenerateKey = async (type: 'RESET_QUOTA' | 'UPGRADE_ROLE', role?: UserRole) => {
        setLoadingAction(true);
        try {
            const key = await generateAdminKey(currentUser.user_id, type, role);
            setGeneratedKey(key);
            loadAllData(); // Refresh logs/stats
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setLoadingAction(false);
        }
    };

    const handleGenerateFeatureKey = async (feature: 'ANALYTICS' | 'AUTOMATION' | 'SEO' | 'THREADS') => {
        setLoadingAction(true);
        try {
            const key = await generateAdminKey(currentUser.user_id, 'UNLOCK_FEATURE', undefined, feature);
            setGeneratedKey(key);
            loadAllData();
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setLoadingAction(false);
        }
    };

    const handleGeneratePointsKey = async (amount: number) => {
        setLoadingAction(true);
        try {
            const key = await generateAdminKey(currentUser.user_id, 'ADD_POINTS', undefined, undefined, amount);
            setGeneratedKey(key);
            loadAllData();
        } catch (e: any) {
            alert(`生成失敗: ${e.message}`);
        } finally {
            setLoadingAction(false);
        }
    };

    const toggleDryRun = () => { 
        updateSystemConfig({ dryRunMode: !config.dryRunMode }); 
        loadAllData(); 
    };

    const toggleMaintenance = () => { 
        updateSystemConfig({ maintenanceMode: !config.maintenanceMode }); 
        loadAllData(); 
    };

    return {
        activeTab, setActiveTab,
        stats, users, reports, logs, config,
        apiUsage, apiStatus,
        generatedKey,
        securityTarget, setSecurityTarget,
        loadingAction, dataLoading, dataError,
        loadAllData,
        handleGenerateKey, handleGenerateFeatureKey, handleGeneratePointsKey,
        toggleDryRun, toggleMaintenance
    };
};

// Facebook SDK Type Definition (Simplified)
declare global {
  interface Window {
    fbAsyncInit: () => void;
    FB: any;
  }
}

const FB_SDK_VERSION = 'v19.0';

// Helper to load SDK
export const initFacebookSdk = (appId: string): Promise<void> => {
  return new Promise((resolve, reject) => {
    if (window.FB) {
      resolve();
      return;
    }

    window.fbAsyncInit = function() {
      window.FB.init({
        appId: appId,
        cookie: true,
        xfbml: true,
        version: FB_SDK_VERSION
      });
      resolve();
    };

    // Load the SDK asynchronously
    (function(d, s, id) {
      var js, fjs = d.getElementsByTagName(s)[0];
      if (d.getElementById(id)) return;
      js = d.createElement(s) as HTMLScriptElement; 
      js.id = id;
      js.src = "https://connect.facebook.net/en_US/sdk.js";
      if (fjs && fjs.parentNode) fjs.parentNode.insertBefore(js, fjs);
    }(document, 'script', 'facebook-jssdk'));
  });
};

export interface FacebookPage {
  id: string;
  name: string;
  access_token: string;
  category?: string;
  tasks?: string[];
}

export const loginAndGetPages = async (): Promise<FacebookPage[]> => {
  if (!window.FB) throw new Error("Facebook SDK not loaded.");

  return new Promise((resolve, reject) => {
    // 1. Login
    window.FB.login((response: any) => {
      if (response.authResponse) {
        // 2. Fetch Accounts (Pages)
        // requesting fields needed for operation
        window.FB.api('/me/accounts', { fields: 'name,id,access_token,category,tasks' }, (pageResponse: any) => {
            if (pageResponse && !pageResponse.error) {
                resolve(pageResponse.data as FacebookPage[]);
            } else {
                reject(new Error(pageResponse.error?.message || "Failed to fetch pages"));
            }
        });
      } else {
        reject(new Error("User cancelled login or did not fully authorize."));
      }
    }, { 
        // 3. Permissions Scope (Updated)
        // read_insights: Required for page_impressions, page_fans_gender_age
        // pages_read_engagement: Required for comments/likes
        // pages_manage_posts: Required for publishing
        // pages_messaging: Required for auto-reply (Messenger)
        scope: 'public_profile,pages_show_list,pages_read_engagement,pages_manage_posts,read_insights,pages_messaging' 
    });
  });
};

