export default SettingsForm;

import React, { useState, useEffect, useRef } from 'react';
import { BrandSettings } from '../../../types';
import { fetchRecentPostCaptions } from '../../../services/facebookService';
import { analyzeBrandTone } from '../../../services/geminiService';
import { checkAndUseQuota, getCurrentUser } from '../../../services/authService';
import { loginAndGetPages, initFacebookSdk, FacebookPage } from '../../../services/facebookAuth';

const INDUSTRIES = [
    "數位行銷", "餐飲美食", "美妝保養", "旅遊住宿", "3C電子", "服飾穿搭", 
    "教育培訓", "房地產", "金融理財", "醫療保健", "寵物用品", "居家生活", "運動健身"
];

// Helper to get Env safely
const getFbAppId = () => {
    const env = (import.meta as any).env || {};
    if (env.VITE_FB_APP_ID) return env.VITE_FB_APP_ID;
    if (env.REACT_APP_FB_APP_ID) return env.REACT_APP_FB_APP_ID;
    return '';
};

export const useBrandSettings = (
    initialSettings: BrandSettings, 
    onSave: (settings: BrandSettings) => void
) => {
    const [formData, setFormData] = useState<BrandSettings>(initialSettings);
    const [isAnalyzingTone, setIsAnalyzingTone] = useState(false);

    // Industry UI State
    const [industrySelectValue, setIndustrySelectValue] = useState<string>('');
    const [showCustomIndustry, setShowCustomIndustry] = useState(false);

    // Facebook OAuth State
    const [fbPages, setFbPages] = useState<FacebookPage[]>([]);
    const [isFbLoading, setIsFbLoading] = useState(false);
    const [isFbSdkReady, setIsFbSdkReady] = useState(false);

    const fileInputRef = useRef<HTMLInputElement>(null);

    // Initialization
    useEffect(() => {
        setFormData(initialSettings);

        // Industry Logic
        if (initialSettings.industry) {
            if (INDUSTRIES.includes(initialSettings.industry)) {
                setIndustrySelectValue(initialSettings.industry);
                setShowCustomIndustry(false);
            } else {
                setIndustrySelectValue('other');
                setShowCustomIndustry(true);
            }
        } else {
            setIndustrySelectValue('');
            setShowCustomIndustry(false);
        }

        // FB SDK
        const appId = getFbAppId();
        if (appId) {
            initFacebookSdk(appId).then(() => setIsFbSdkReady(true)).catch(console.error);
        }
    }, [initialSettings]);

    const handleChange = (field: keyof BrandSettings, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const handleIndustrySelectChange = (val: string) => {
        setIndustrySelectValue(val);
        if (val === 'other') {
            setShowCustomIndustry(true);
            handleChange('industry', '');
        } else {
            setShowCustomIndustry(false);
            handleChange('industry', val);
        }
    };

    // Competitor List Logic
    const handleCompetitorChange = (index: number, val: string) => {
        const newList = [...(formData.competitorUrls || [])];
        newList[index] = val;
        handleChange('competitorUrls', newList);
    };

    const addCompetitorField = () => {
        const current = formData.competitorUrls || [];
        if (current.length >= 5) return;
        handleChange('competitorUrls', [...current, '']);
    };

    const removeCompetitorField = (index: number) => {
        const newList = (formData.competitorUrls || []).filter((_, i) => i !== index);
        handleChange('competitorUrls', newList);
    };

    // AI Tone Analysis
    const handleAutoAnalyzeStyle = async () => {
        if (!formData.facebookPageId || !formData.facebookToken) {
            return alert("請先填寫並驗證 Facebook Page ID 與 Token");
        }

        const user = getCurrentUser();
        if (!user) return alert("請先登入");

        const COST = 5;
        const allowed = await checkAndUseQuota(user.uid, COST, 'ANALYZE_TONE');
        if (!allowed) return; 

        setIsAnalyzingTone(true);
        try {
            const posts = await fetchRecentPostCaptions(formData.facebookPageId, formData.facebookToken, 15);
            if (posts.length < 3) throw new Error("貼文數量過少，無法有效分析 (至少需要 3 篇)。");
            const styleGuide = await analyzeBrandTone(posts);
            setFormData(prev => ({ ...prev, brandStyleGuide: styleGuide }));
            alert(`✅ 分析完成！已更新「品牌風格指南」。(扣除 ${COST} 點)`);
        } catch (e: any) {
            alert(`分析失敗: ${e.message}`);
        } finally {
            setIsAnalyzingTone(false);
        }
    };

    // Facebook Connect
    const handleConnectFacebook = async () => {
        if (!isFbSdkReady) {
            const appId = getFbAppId();
            alert(`⚠️ 無法啟動 Facebook 登入。\n原因：${!appId ? '未設定 App ID' : 'SDK 被瀏覽器插件阻擋 (請關閉 AdBlock)'}`);
            return;
        }

        setIsFbLoading(true);
        try {
            const pages = await loginAndGetPages();
            setFbPages(pages);
            if (pages.length === 1) selectPage(pages[0]);
            else if (pages.length === 0) alert("沒有發現任何粉絲專頁，或未授權管理權限。");
        } catch (e: any) {
            alert(`FB 登入失敗: ${e.message}`);
        } finally {
            setIsFbLoading(false);
        }
    };

    const selectPage = (page: FacebookPage) => {
        setFormData(prev => ({
            ...prev,
            facebookPageId: page.id,
            facebookToken: page.access_token,
            brandName: prev.brandName || page.name
        }));
        setFbPages([]);
        alert(`已成功連結：${page.name}`);
    };

    // Logo Upload
    const handleLogoUpload = (file: File) => {
        const reader = new FileReader();
        reader.onload = (event) => {
            const base64 = event.target?.result as string;
            const img = new Image();
            img.onload = () => {
                const canvas = document.createElement('canvas');
                const MAX_WIDTH = 300;
                const scale = MAX_WIDTH / img.width;
                canvas.width = MAX_WIDTH;
                canvas.height = img.height * scale;
                const ctx = canvas.getContext('2d');
                ctx?.drawImage(img, 0, 0, canvas.width, canvas.height);
                const resizedBase64 = canvas.toDataURL('image/png', 0.8);
                setFormData(prev => ({ ...prev, logoUrl: resizedBase64 }));
            };
            img.src = base64;
        };
        reader.readAsDataURL(file);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        onSave(formData);
        alert("品牌設定已同步至雲端！");
    };

    return {
        formData, handleChange,
        industrySelectValue, handleIndustrySelectChange, showCustomIndustry, INDUSTRIES,
        competitorHandlers: { handleCompetitorChange, addCompetitorField, removeCompetitorField },
        fbState: { isAnalyzingTone, isFbLoading, isFbSdkReady, fbPages },
        fbActions: { handleAutoAnalyzeStyle, handleConnectFacebook, selectPage },
        logoActions: { fileInputRef, handleLogoUpload },
        handleSubmit
    };
};

import { db, firebase, isMock } from '../firebase';
import { executeWithQueue } from '../queueService';

// #region Types & Constants

export const Type = {
  STRING: 'STRING',
  NUMBER: 'NUMBER',
  INTEGER: 'INTEGER',
  BOOLEAN: 'BOOLEAN',
  ARRAY: 'ARRAY',
  OBJECT: 'OBJECT'
};

const CACHE_TTL = 12 * 60 * 60 * 1000; // 12 Hours Cache

// #region Helper Utilities

export const cleanJsonText = (text: string): string => {
  return text.replace(/```json/g, '').replace(/```/g, '').trim();
};

/**
 * Removes Markdown formatting that Facebook/Instagram/Threads don't support.
 * e.g., "**Bold**" -> "Bold", "## Title" -> "Title"
 * UPDATE: Strictly preserves newlines for paragraph readability.
 */
export const cleanSocialMediaText = (text: string): string => {
    if (!text) return "";
    let clean = text;

    // 1. Remove Bold/Italic asterisks (**text**, *text*)
    // Use non-greedy match
    clean = clean.replace(/\*\*(.*?)\*\*/g, '$1'); 
    clean = clean.replace(/\*(.*?)\*/g, '$1');

    // 2. Remove Headers (## Title)
    clean = clean.replace(/^#+\s+/gm, '');

    // 3. Fix Escaped Newlines (literal "\n" to real newline)
    // Sometimes AI returns "\\n" as a string literal
    clean = clean.split('\\n').join('\n');

    // 4. Ensure Paragraphs (Optional: Ensure max 2 newlines to prevent huge gaps, but min 1)
    // This regex replaces 3 or more newlines with 2.
    clean = clean.replace(/\n{3,}/g, '\n\n');

    return clean.trim();
};

export const decodeHtml = (html: string): string => {
  const txt = document.createElement("textarea");
  txt.innerHTML = html;
  return txt.value;
};

export const shuffleArray = <T>(array: T[]): T[] => {
    const newArray = [...array];
    let currentIndex = newArray.length, randomIndex;
    while (currentIndex !== 0) {
      randomIndex = Math.floor(Math.random() * currentIndex);
      currentIndex--;
      [newArray[currentIndex], newArray[randomIndex]] = [
        newArray[randomIndex], newArray[currentIndex]];
    }
    return newArray;
};

// #region System Cache

export const getSystemCache = async (key: string) => {
    if (isMock) {
        const item = localStorage.getItem('cache_' + key);
        if (!item) return null;
        try {
            const parsed = JSON.parse(item);
            if (Date.now() > parsed.expiry) {
                localStorage.removeItem('cache_' + key);
                return null;
            }
            return parsed.data;
        } catch(e) { return null; }
    }

    try {
        const doc = await db.collection('system_cache').doc(key).get();
        if (doc.exists) {
            const data = doc.data();
            if (data.expiry > Date.now()) {
                return JSON.parse(data.content);
            }
        }
    } catch (e) { 
        console.warn("Cache Read Error (Permission/Network)", e); 
    }
    return null;
};

export const setSystemCache = async (key: string, data: any) => {
    const expiry = Date.now() + CACHE_TTL;

    if (isMock) {
        localStorage.setItem('cache_' + key, JSON.stringify({ data, expiry }));
        return;
    }

    try {
        await db.collection('system_cache').doc(key).set({
            content: JSON.stringify(data),
            expiry
        });
    } catch (e) { 
        console.warn("Cache Write Error (Permission/Network)", e); 
    }
};

// #region Backend API Caller

export const callBackend = async (action: string, payload: any) => {
    console.log(`[Backend Call] Action: ${action}`, payload.model ? `Model: ${payload.model}` : '');

    return executeWithQueue(action, async () => {
        const controller = new AbortController();
        // TIMEOUT EXTENDED: 300s (5 minutes) for Gemini 3 Pro Reasoning + Search
        const timeoutId = setTimeout(() => controller.abort(), 300000); 

        try {
            const res = await fetch('/api/gemini', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action, payload }),
                signal: controller.signal
            });

            clearTimeout(timeoutId);

            if (!res.ok) {
                let errorMsg = `HTTP Error ${res.status}`;
                try {
                    const err = await res.json();
                    if (err.error) errorMsg = err.error;
                } catch (e) {}

                // Retry logic for 504 Gateway Timeout (Vercel Hard Limit)
                if (res.status === 504) {
                    throw new Error("伺服器運算逾時 (Vercel 504)。請縮小搜尋範圍或稍後再試。");
                }

                throw new Error(errorMsg);
            }

            return await res.json();
        } catch (e: any) {
            clearTimeout(timeoutId);
            console.error(`Backend API Error [${action}]:`, e);

            if (e.name === 'AbortError') {
                throw new Error("請求逾時 (Server Timeout)。AI 思考或搜尋時間過長，請稍後再試。");
            }
            throw e;
        }
    });
};

export const getApiServiceStatus = async () => {
    try {
        return await callBackend('getServiceStatus', {});
    } catch (e) {
        console.warn("Failed to get API status", e);
        return { keyStatus: [], providers: { openai: false, ideogram: false, grok: false } };
    }
};

