}

export const TopicSelector: React.FC<Props> = ({ topic, setTopic, mode, setMode, trends, onNext, onSetSourceUrl }) => {
    // Local display state for shuffling
    const [displayTrends, setDisplayTrends] = useState<TrendingTopic[]>([]);

    // Sync trends data to local display when it loads
    React.useEffect(() => {
        if (trends.data.length > 0) {
            setDisplayTrends(trends.data);
        }
    }, [trends.data]);

    const handleRefresh = () => {
        // If we have data, shuffle it first for instant "refresh" feeling
        if (trends.data.length > 0) {
            setDisplayTrends(prev => shuffleArray([...prev]));
        }
        // Then trigger actual load with refresh flag
        trends.load(true);
    };

    const handleTopicClick = (t: TrendingTopic) => {
        setTopic(t.title);
        if (onSetSourceUrl && t.url) {
            onSetSourceUrl(t.url);
        }
    };

    return (
        <div className="max-w-4xl mx-auto space-y-8 md:space-y-12 animate-fade-in pt-4 md:pt-10">
            <div className="text-center space-y-3">
                <h2 className="text-3xl md:text-5xl font-black text-white tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
