// Opportunity Scout Logic (Unchanged)...
const patchUrl = (item: any, validLinks: string[]): string => {
    if (item.url && validLinks.includes(item.url)) return item.url;
    let cleanTitle = (item.title || item.content || '').trim();
    cleanTitle = cleanTitle.replace(/\s-\s(Dcard|PTT|看板|Threads|美妝|閒聊).*$/i, '');
    const siteKeyword = item.url?.includes('threads') ? 'site:threads.net' : 
                       item.url?.includes('dcard') ? 'site:dcard.tw' : 
                       item.url?.includes('ptt') ? 'site:ptt.cc' : '';
    const query = `${siteKeyword} ${cleanTitle}`.trim();
    return `https://www.google.com/search?q=${encodeURIComponent(query)}`;
};

const executeSearchQuery = async (query: string, keyword: string, intentContext: string) => {
    const prompt = `
    Role: Commercial Opportunity Hunter (Taiwan).
    Task: Find recent real user discussions on Threads, Dcard, and PTT matching the query.
    Context: We are looking for "${intentContext}" regarding "${keyword}".
    [SEARCH QUERY] ${query}
    [FILTERING RULES] 1. Last 1 month. 2. Ignore ads/news. 3. Real human intent.
    [Output Schema] JSON Array: [{ "title", "content", "url", "username", "reasoning", "intentScore" (1-10), "replyCount" }]
    IMPORTANT: Output ONLY the raw JSON string.
    `;

    try {
        const response = await callBackend('generateContent', {
            model: "gemini-2.5-flash",
            contents: prompt,
            config: { tools: [{ googleSearch: {} }] }
        });
        const validLinks = response.groundingMetadata?.groundingChunks?.map((chunk: any) => chunk.web?.uri) || [];
        const jsonStr = cleanJsonText(response.text || '[]');
        const data = JSON.parse(jsonStr);
        if (Array.isArray(data)) {
            return data.map((item: any) => ({ ...item, url: patchUrl(item, validLinks) }));
        }
        return [];
    } catch (e) {
        console.error("Search failed:", e);
        return [];
    }
};

export const findThreadsOpportunities = async (keyword: string): Promise<OpportunityPost[]> => {
    const now = new Date();
    now.setMonth(now.getMonth() - 1);
    const dateStr = now.toISOString().split('T')[0]; 
    const q1 = `(site:threads.net OR site:dcard.tw OR site:ptt.cc) "${keyword}" (心得 OR 評價 OR 避雷 OR 缺點 OR 後悔) after:${dateStr}`;
    const q2 = `(site:threads.net OR site:dcard.tw OR site:ptt.cc) "${keyword}" (請益 OR 選手 OR 比較 OR 哪裡買 OR 好用嗎) after:${dateStr}`;
    const q3 = `(site:threads.net OR site:dcard.tw OR site:ptt.cc) "${keyword}" (推薦 OR 熱門 OR 分享) after:${dateStr}`;

    const r1 = await executeSearchQuery(q1, keyword, "Reviews & Issues");
    const r2 = await executeSearchQuery(q2, keyword, "Buying Questions");
    const r3 = await executeSearchQuery(q3, keyword, "General Discussions");

    const allResults = [...r1, ...r2, ...r3];
    const uniqueMap = new Map();
    allResults.forEach(item => {
        let key = item.url.includes('google.com/search') ? item.title : item.url;
        if (!uniqueMap.has(key)) uniqueMap.set(key, item);
        else {
            const existing = uniqueMap.get(key);
            if (item.intentScore > existing.intentScore) uniqueMap.set(key, item);
        }
    });
    return Array.from(uniqueMap.values()).sort((a, b) => b.intentScore - a.intentScore);
};

import { useState, useEffect } from 'react';
import { BrandSettings, Post, TrendingTopic, ImageIntent } from '../../../types';
import { getTrendingTopics, generatePostDraft, generateImage, applyWatermark, generateViralContent, generateImagePromptString, compositeImageWithText } from '../../../services/geminiService';
import { publishPostToFacebook } from '../../../services/facebookService';
import { checkAndUseQuota } from '../../../services/authService';
import { useAuth } from '../../../context/AuthContext';
import { shuffleArray } from '../../../services/gemini/core'; // Import shuffle

export interface PostGeneratorState {
    step: 1 | 2;
    topic: string;
    mode: 'brand' | 'viral';
    draft: {
        caption: string;
        firstComment: string;
        imagePrompt: string;
    };
    imageSettings: {
        intent: ImageIntent;
        renderMode: 'plain' | 'ai_text' | 'smart_layout';
        customText: string;
        layoutTitle: string;
        layoutSubtitle: string;
    };
    media: {
        url?: string;
        isGenerating: boolean;
        phase: string;
    };
    scheduling: {
        date: string;
        syncInstagram: boolean;
        isPublishing: boolean;
        result: { success: boolean; msg: string } | null;
    };
    trends: {
        data: TrendingTopic[];
        loading: boolean;
    };
}

export const usePostGenerator = (
    settings: BrandSettings, 
    onPostCreated: (post: Post) => void,
    onQuotaUpdate: () => void,
    editPost?: Post | null,
    initialTopic?: string,
    initialSourceUrl?: string
) => {
    const { userProfile } = useAuth();

    // --- State Management ---
    const [step, setStep] = useState<1 | 2>(1);
    const [topic, setTopic] = useState('');
    const [mode, setMode] = useState<'brand' | 'viral'>('brand');
    const [sourceUrl, setSourceUrl] = useState(''); // NEW Source URL

    // Trend State
    const [trendingTopics, setTrendingTopics] = useState<TrendingTopic[]>([]);
    const [isLoadingTrends, setIsLoadingTrends] = useState(false);

    // Draft State
    const [draft, setDraft] = useState({ caption: '', firstComment: '', imagePrompt: '' });
    const [isGeneratingDraft, setIsGeneratingDraft] = useState(false);

    // Image State
    const [imageIntent, setImageIntent] = useState<ImageIntent>('lifestyle');
    const [renderMode, setRenderMode] = useState<'plain' | 'ai_text' | 'smart_layout'>('plain');
    const [customImageText, setCustomImageText] = useState('');
    const [layoutTitle, setLayoutTitle] = useState('');
    const [layoutSubtitle, setLayoutSubtitle] = useState('');
    const [mediaUrl, setMediaUrl] = useState<string | undefined>(undefined);
    const [isGeneratingMedia, setIsGeneratingMedia] = useState(false);
    const [generatingPhase, setGeneratingPhase] = useState('');

    // Publishing State
    const [scheduleDate, setScheduleDate] = useState('');
    const [syncInstagram, setSyncInstagram] = useState(false);
    const [isPublishing, setIsPublishing] = useState(false);
    const [publishResult, setPublishResult] = useState<{success: boolean, msg: string} | null>(null);

    // --- Effects ---

    // 1. Initialize from Edit Post or Topic
    useEffect(() => {
        if (editPost) {
            setStep(2);
            setTopic(editPost.topic);
            setDraft({ 
                caption: editPost.caption, 
                firstComment: editPost.firstComment || '', 
                imagePrompt: editPost.mediaPrompt 
            });
            setMediaUrl(editPost.mediaUrl);
            setScheduleDate(editPost.scheduledDate || '');
            setSyncInstagram(!!editPost.syncInstagram);
        } else if (initialTopic) {
            setTopic(initialTopic);
            if (initialSourceUrl) setSourceUrl(initialSourceUrl);
            setStep(1);
        }
    }, [editPost, initialTopic, initialSourceUrl]);

    // 2. Smart Layout Auto-fill
    useEffect(() => {
        if (draft.caption && !layoutTitle) {
            setLayoutTitle(topic);
            const priceMatch = draft.caption.match(/\$\d+(?:,\d+)?/);
            if (priceMatch) setLayoutSubtitle(`${priceMatch[0]} 起`);
        }
    }, [draft.caption]);

    // --- Actions ---

    const loadTrends = async (refresh: boolean = false) => {
        if (!userProfile) return alert("請先登入");

        // Strategy: If refreshing via button, pay quota to force fetch
        const COST = 3; 
        const allowed = await checkAndUseQuota(userProfile.user_id, COST, 'TREND_SEARCH'); 
        if (!allowed) return; 

        onQuotaUpdate();
        setIsLoadingTrends(true);
        try {
            const query = topic.trim() || settings.industry || '台灣熱門話題';

            // Pass the 'refresh' boolean down to service to bypass 1h cache
            const trends = await getTrendingTopics(query, 10, refresh);

            // Even if refreshed, we shuffle to ensure variety in UI
            setTrendingTopics(shuffleArray(trends));

            if(topic.trim()) alert(`已為您搜尋關於「${query}」的熱門話題！(扣除 ${COST} 點)`);
        } catch (e) { console.error(e); }
        finally { setIsLoadingTrends(false); }
    };

    const generateDraft = async () => {
        if (!topic || !userProfile) return;

        const allowed = await checkAndUseQuota(userProfile.user_id, 5, 'GENERATE_POST_DRAFT');
        if (!allowed) return; 

        onQuotaUpdate();
        setStep(2);
        setIsGeneratingDraft(true);
        setMediaUrl(undefined); 

        try {
            if (mode === 'brand') {
                const res = await generatePostDraft(topic, settings, { 
                    length: '150-300字', 
                    ctaList: [], 
                    tempHashtags: '', 
                    includeEngagement: false 
                }, undefined, userProfile.role);

                setDraft({ 
                    caption: res.caption || '', 
                    firstComment: res.ctaText || '', 
                    imagePrompt: '' 
                });
            } else {
                const res = await generateViralContent(topic, {
                    audience: '社群大眾',
                    viralType: 'auto',
                    platform: 'facebook',
                    versionCount: 1
                }, settings);
                setDraft({
                    caption: res.versions?.[0] || '生成內容為空，請重試',
                    firstComment: '',
                    imagePrompt: ''
                });
            }
        } catch (e: any) { 
            alert(`失敗: ${e.message}`); 
            setStep(1); 
        } finally { 
            setIsGeneratingDraft(false); 
        }
    };

    const generateMedia = async () => {
        if (!userProfile || isGeneratingMedia) return;

        if (renderMode === 'ai_text' && !customImageText) return alert("請輸入您想顯示在圖片上的文字，或切換模式。");
        if (renderMode === 'smart_layout' && !layoutTitle) return alert("智慧排版模式需要至少輸入「主標題」。");

        const cost = mediaUrl ? 5 : 8; 
        const allowed = await checkAndUseQuota(userProfile.user_id, cost, 'GENERATE_IMAGE_AI');
        if (!allowed) return;

        onQuotaUpdate();
        setIsGeneratingMedia(true);
        setGeneratingPhase('正在構思畫面...');

        try {
            let finalPrompt = draft.imagePrompt;
            if (!finalPrompt.trim()) {
                 const aiPrompt = await generateImagePromptString(draft.caption, imageIntent, settings);
                 finalPrompt = aiPrompt;
                 setDraft(prev => ({ ...prev, imagePrompt: aiPrompt }));
            }

            setGeneratingPhase('AI 設計師繪圖中 (標準畫質)...');

            let url = await generateImage(
                finalPrompt, 
                userProfile.role, 
                settings, 
                imageIntent,
                renderMode === 'ai_text' ? customImageText : undefined,
                renderMode === 'smart_layout'
            );

            if (renderMode === 'smart_layout') {
                setGeneratingPhase('正在進行智慧排版合成...');
                url = await compositeImageWithText(url, layoutTitle, layoutSubtitle, '#FFD700');
            }

            if (settings.logoUrl) {
                setGeneratingPhase('正在壓上品牌浮水印...');
                url = await applyWatermark(url, settings.logoUrl);
            }
            setMediaUrl(url);
        } catch (e: any) { 
            alert(`製圖失敗: ${e.message}`); 
        } finally { 
            setIsGeneratingMedia(false); 
            setGeneratingPhase('');
        }
    };

    const publish = async (isScheduled: boolean) => {
        if (!userProfile || isPublishing) return;
        let scheduledUnixTime: number | undefined = undefined;

        if (isScheduled) {
            if (!scheduleDate) return alert("請選擇預計發佈時間");
            const targetTime = new Date(scheduleDate).getTime();
            const now = Date.now();
            const diffMinutes = (targetTime - now) / 1000 / 60;
            if (diffMinutes < 10) return alert("FB 規定：排程時間必須在「未來 10 分鐘」之後。");
            if (diffMinutes > 30 * 24 * 60) return alert("FB 規定：排程時間不能超過 30 天。");
            scheduledUnixTime = Math.floor(targetTime / 1000);
        }

        setIsPublishing(true);
        try {
            const newPost: Post = {
              id: editPost ? editPost.id : Date.now().toString(),
              userId: userProfile.user_id,
              topic,
              caption: draft.caption, 
              firstComment: draft.firstComment,
              mediaPrompt: draft.imagePrompt,
              mediaType: 'image',
              mediaUrl,
              status: isScheduled ? 'scheduled' : 'published',
              scheduledDate: isScheduled ? scheduleDate : undefined, 
              syncInstagram,
              createdAt: editPost ? editPost.createdAt : Date.now()
            };

            const res = await publishPostToFacebook(
                settings.facebookPageId, 
                settings.facebookToken, 
                draft.caption, 
                mediaUrl, 
                draft.firstComment, 
                syncInstagram,
                scheduledUnixTime
            );

            if (res.success) {
                newPost.publishedUrl = res.url;
                newPost.status = isScheduled ? 'scheduled' : 'published';
                await onPostCreated(newPost);

                if (isScheduled) setPublishResult({ success: true, msg: "✅ 已成功傳送至 Facebook 排程系統！" });
                else setPublishResult({ success: true, msg: "✅ 貼文已成功發佈！" });
            } else {
                newPost.status = 'failed';
                newPost.errorLog = res.error;
                await onPostCreated(newPost);
                setPublishResult({ success: false, msg: `❌ 發佈失敗: ${res.error}` });
            }

        } catch (err: any) { 
            setPublishResult({ success: false, msg: `錯誤: ${err.message}` }); 
        } finally { 
            setIsPublishing(false); 
        }
    };

    return {
        // State
        step, setStep,
        topic, setTopic,
        mode, setMode,
        sourceUrl, setSourceUrl,
        trends: { data: trendingTopics, loading: isLoadingTrends, load: loadTrends },
        draft: { data: draft, setData: setDraft, isGenerating: isGeneratingDraft, generate: generateDraft },
        image: {
            intent: imageIntent, setIntent: setImageIntent,
            renderMode, setRenderMode,
            customText: customImageText, setCustomText: setCustomImageText,
            layoutTitle, setLayoutTitle,
            layoutSubtitle, setLayoutSubtitle,
            url: mediaUrl, setUrl: setMediaUrl,
            isGenerating: isGeneratingMedia,
            phase: generatingPhase,
            generate: generateMedia
        },
        publish: {
            scheduleDate, setScheduleDate,
            syncInstagram, setSyncInstagram,
            isPublishing,
            result: publishResult, setResult: setPublishResult,
            execute: publish
        }
    };
};

import { db, firebase, isMock } from '../firebase';
import { executeWithQueue } from '../queueService';

// #region Types & Constants

export const Type = {
  STRING: 'STRING',
  NUMBER: 'NUMBER',
  INTEGER: 'INTEGER',
  BOOLEAN: 'BOOLEAN',
  ARRAY: 'ARRAY',
  OBJECT: 'OBJECT'
};

// UPDATED: Cache lives for at most 24 Hours (User Requirement)
const CACHE_TTL = 24 * 60 * 60 * 1000; 

// #region Helper Utilities

export const cleanJsonText = (text: string): string => {
  return text.replace(/```json/g, '').replace(/```/g, '').trim();
};

/**
 * Removes Markdown formatting that Facebook/Instagram/Threads don't support.
 * e.g., "**Bold**" -> "Bold", "## Title" -> "Title"
 * STRICTLY preserves newlines for paragraph readability.
 */
export const cleanSocialMediaText = (text: string): string => {
    if (!text) return "";
    let clean = text;

    // 1. Remove Bold/Italic asterisks (**text**, *text*)
    clean = clean.replace(/\*\*(.*?)\*\*/g, '$1'); 
    clean = clean.replace(/\*(.*?)\*/g, '$1');

    // 2. Remove Headers (## Title)
    clean = clean.replace(/^#+\s+/gm, '');

    // 3. Fix Escaped Newlines (literal "\n" to real newline)
    clean = clean.split('\\n').join('\n');

    // 4. Ensure Paragraphs (Ensure max 2 newlines to prevent huge gaps)
    clean = clean.replace(/\n{3,}/g, '\n\n');

    return clean.trim();
};

export const decodeHtml = (html: string): string => {
  const txt = document.createElement("textarea");
  txt.innerHTML = html;
  return txt.value;
};

export const shuffleArray = <T>(array: T[]): T[] => {
    const newArray = [...array];
    let currentIndex = newArray.length, randomIndex;
    while (currentIndex !== 0) {
      randomIndex = Math.floor(Math.random() * currentIndex);
      currentIndex--;
      [newArray[currentIndex], newArray[randomIndex]] = [
        newArray[randomIndex], newArray[currentIndex]];
    }
    return newArray;
};

export const generateTopicId = (title: string): string => {
    const hash = Math.abs(title.split('').reduce((a,b)=>{a=((a<<5)-a)+b.charCodeAt(0);return a&a},0));
    return `trend_${hash}`;
};

// #region System Cache

export const getSystemCache = async (key: string) => {
    if (isMock) {
        const item = localStorage.getItem('cache_' + key);
        if (!item) return null;
        try {
            const parsed = JSON.parse(item);
            if (Date.now() > parsed.expiry) {
                localStorage.removeItem('cache_' + key);
                return null;
            }
            return parsed.data;
        } catch(e) { return null; }
    }

    try {
        const doc = await db.collection('system_cache').doc(key).get();
        if (doc.exists) {
            const data = doc.data();
            // Check Expiry
            if (data.expiry > Date.now()) {
                return JSON.parse(data.content);
            }
        }
    } catch (e) { 
        console.warn("Cache Read Error (Permission/Network)", e); 
    }
    return null;
};

export const setSystemCache = async (key: string, data: any) => {
    const expiry = Date.now() + CACHE_TTL;

    if (isMock) {
        localStorage.setItem('cache_' + key, JSON.stringify({ data, expiry }));
        return;
    }

    try {
        await db.collection('system_cache').doc(key).set({
            content: JSON.stringify(data),
            expiry
        });
    } catch (e) { 
        console.warn("Cache Write Error (Permission/Network)", e); 
    }
};

// #region Backend API Caller

export const callBackend = async (action: string, payload: any) => {
    console.log(`[Backend Call] Action: ${action}`, payload.model ? `Model: ${payload.model}` : '');

    return executeWithQueue(action, async () => {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 300000); 

        try {
            const res = await fetch('/api/gemini', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action, payload }),
                signal: controller.signal
            });

            clearTimeout(timeoutId);

            if (!res.ok) {
                let errorMsg = `HTTP Error ${res.status}`;
                try {
                    const err = await res.json();
                    if (err.error) errorMsg = err.error;
                } catch (e) {}

                if (res.status === 504) {
                    throw new Error("伺服器運算逾時 (Vercel 504)。請縮小搜尋範圍或稍後再試。");
                }

                throw new Error(errorMsg);
            }

            return await res.json();
        } catch (e: any) {
            clearTimeout(timeoutId);
            console.error(`Backend API Error [${action}]:`, e);

            if (e.name === 'AbortError') {
                throw new Error("請求逾時 (Server Timeout)。AI 思考或搜尋時間過長，請稍後再試。");
            }
            throw e;
        }
    });
};

