 * - forceRefresh: User clicked button, bypass cache.
 */
export const getMarketData = async (
    category: StockCategory = "general", 
    forceRefresh: boolean = false
): Promise<StockTrend[]> => {

    const SOFT_TTL = 60 * 60 * 1000; // 1 Hour (Freshness)
