// --- CORE LOGIC: AUTO PILOT ---

async function runAutoPilotEngine(db) {
    console.log("[AutoPilot] Engine Starting...");
    const ai = await getGeminiClient();

    // 1. Time Calculation (Taipei Time UTC+8)
    const now = new Date();
    const utc = now.getTime() + (now.getTimezoneOffset() * 60000);
    const taipeiTime = new Date(utc + (3600000 * 8));

    const currentHour = taipeiTime.getHours();
    const currentDay = taipeiTime.getDay(); // 0 (Sun) - 6 (Sat)

    // Timestamp for "Start of Today" in Taipei to check duplication
    const startOfToday = new Date(taipeiTime);
    startOfToday.setHours(0,0,0,0);
    const startOfTodayTs = startOfToday.getTime();

    console.log(`[AutoPilot] Time Check: Day ${currentDay}, Hour ${currentHour} (Taipei)`);

    // 2. Fetch All Brand Settings
    const settingsSnap = await db.collection('brand_settings').get();
    let processedCount = 0;

    for (const doc of settingsSnap.docs) {
        const userId = doc.id;
        const settings = doc.data();
        const config = settings.autoPilot;

        // --- FILTERING ---
        if (!config || !config.enabled) continue;

        // Day Check
        if (config.frequency === 'weekly' && config.postWeekDays && !config.postWeekDays.includes(currentDay)) continue;

        // Time Check (Simple hour matching)
        // config.postTime format "09:00"
        const configHour = parseInt(config.postTime.split(':')[0]);
        if (configHour !== currentHour) continue;

        // Duplication Check (Don't run if already ran today)
        if (config.lastRunAt && config.lastRunAt > startOfTodayTs) {
            console.log(`[AutoPilot] User ${userId} already ran today.`);
            continue;
        }

        // Quota Check
        const userRef = db.collection('users').doc(userId);
        const userDoc = await userRef.get();
        const userData = userDoc.data();

        // Cost: 15 points
        if (!userData || userData.quota_used + 15 > userData.quota_total) {
            console.log(`[AutoPilot] User ${userId} quota exceeded. Skipped.`);
            continue;
        }

        // --- EXECUTION ---
        try {
            console.log(`[AutoPilot] Executing for User ${userId}...`);

            // A. Generate Topic
            let topic = '';
            if (config.source === 'keywords' && config.keywords.length > 0) {
                topic = config.keywords[Math.floor(Math.random() * config.keywords.length)];
            } else {
                const searchResp = await ai.models.generateContent({
                    model: 'gemini-2.5-flash',
                    contents: `找出目前台灣關於「${settings.industry}」的一個熱門社群話題。只回傳話題標題。`,
                    config: { tools: [{ googleSearch: {} }] }
                });
                topic = searchResp.text?.trim() || `${settings.industry} 熱門趨勢`;
            }

            // B. Generate Content (Draft)
            const draftResp = await ai.models.generateContent({
                model: "gemini-2.5-flash", // Use flash for speed/cost in cron
                contents: `
                    角色: 專業社群小編。品牌: ${settings.brandName} (${settings.industry})。
                    任務: 針對主題「${topic}」寫一篇 FB 貼文。
                    要求: 繁體中文，親切互動，加入 Emoji。字數 200 字內。
                    Output JSON: { "caption": "...", "imagePrompt": "English prompt for..." }
                `,
                config: { responseMimeType: "application/json" }
            });
            const draft = JSON.parse(draftResp.text || '{}');

            // C. Generate Image (Using Pollinations for stability/speed in Cron)
            // Note: Generating via Gemini Image in Cron is possible but risks timeouts. 
            // Using Pollinations URL is safer for background jobs unless using queues.
            let imageUrl = null;
            if (config.mediaTypePreference !== 'text_only') {
                // Check if user is Pro/Business for better image? 
                // For simplicity in Cron, we use the fastest method.
                if (draft.imagePrompt) {
                    const encoded = encodeURIComponent(draft.imagePrompt);
                    imageUrl = `https://image.pollinations.ai/prompt/${encoded}?n=${userId}&model=flux`;
                }
            }

            // D. Publish
            if (settings.facebookPageId && settings.facebookToken) {
                const fbPostId = await publishToFb(settings.facebookPageId, settings.facebookToken, draft.caption, imageUrl);

                if (fbPostId) {
                    // E. Deduct Quota & Update State
                    await userRef.update({
                        quota_used: admin.firestore.FieldValue.increment(15),
                        updated_at: Date.now()
                    });

                    await db.collection('brand_settings').doc(userId).update({
                        'autoPilot.lastRunAt': Date.now()
                    });

                    // Log
                    await db.collection('usage_logs').add({
                        uid: userId,
                        act: 'AUTOPILOT_EXEC',
                        topic: topic,
                        res: 'Success',
                        ts: Date.now()
                    });

                    processedCount++;
                }
            }

        } catch (err) {
            console.error(`[AutoPilot] Job Failed for ${userId}`, err);
        }

        // Delay to prevent rate limits
        await delay(1000); 
    }

    return processedCount;
}

